    --box-border-top: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-right: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-bottom: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-left: var(--box-border-width) var(--box-border-style) var(--box-border-color);

    /* 新增：阴影效果 - 火焰发光 */
    --shadow-primary: 0 4px 20px rgba(255, 87, 51, 0.4), 0 8px 30px rgba(255, 138, 0, 0.3);
    --shadow-accent: 0 4px 20px rgba(255, 51, 51, 0.4), 0 8px 30px rgba(255, 87, 51, 0.3);
    --shadow-elevated: 0 10px 40px rgba(255, 0, 0, 0.3), 0 0 20px rgba(255, 87, 51, 0.2);

    /* 新增：动画效果 */
    --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-bounce: 400ms cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

/* ==================== 日间模式 - 森林绿意 ==================== */
[data-theme="light"] {
    /* ==================== 🔴 渐变背景颜色（必须修改） ==================== */
    /* 基础渐变背景色 - 浅绿到浅黄渐变（森林清晨效果） */
    --bg-gradient-0: linear-gradient(135deg, #f0fff4 0%, #e6ffee 50%, #f0fff0 100%);  /* 🔴 最深层渐变背景 */
    --bg-gradient-1: linear-gradient(135deg, #ffffff 0%, #f8fff8 50%, #f5fff5 100%);  /* 🔴 主渐变背景 */
    --bg-gradient-2: linear-gradient(135deg, #f5fff9 0%, #f0fff0 50%, #f2fff2 100%);  /* 🔴 次要渐变背景 */
    --bg-gradient-3: linear-gradient(135deg, #ecfff2 0%, #e8ffeb 50%, #eaffea 100%);  /* 🔴 三级渐变背景 */
    --bg-gradient-4: linear-gradient(135deg, #e2ffec 0%, #deffe6 50%, #e0ffe0 100%);  /* 🔴 四级渐变背景 */

    /* 表面渐变颜色 - 用于卡片、面板、按钮等（叶片表面效果） */
    --surface-gradient-0: linear-gradient(145deg, #ffffff 0%, #f8fff8 100%);  /* 🔴 表面0渐变 */
    --surface-gradient-1: linear-gradient(145deg, #f5fff9 0%, #f0fff0 100%);  /* 🔴 表面1渐变 */
    --surface-gradient-2: linear-gradient(145deg, #ecfff2 0%, #e8ffeb 100%);  /* 🔴 表面2渐变（按钮默认背景） */
    --surface-gradient-3: linear-gradient(145deg, #e2ffec 0%, #deffe6 100%);  /* 🔴 表面3渐变（按钮hover背景） */

    /* 兼容纯色变量（用于不支持渐变的元素） */
    --bg-0: #f0fff4;
    --bg-1: #ffffff;
    --bg-2: #f5fff9;
    --bg-3: #ecfff2;
    --bg-4: #e2ffec;

    --surface-0: #ffffff;
    --surface-1: #f5fff9;
    --surface-2: #ecfff2;
    --surface-3: #e2ffec;

    /* 边框颜色 - 绿叶色渐变边框 */
    --border-subtle: rgba(56, 142, 60, 0.15);
    --border-base: linear-gradient(90deg, rgba(56, 142, 60, 0.3), rgba(104, 159, 56, 0.3));
    --border-strong: linear-gradient(90deg, rgba(56, 142, 60, 0.4), rgba(104, 159, 56, 0.4));
    --border-emphasis: linear-gradient(90deg, rgba(56, 142, 60, 0.6), rgba(104, 159, 56, 0.6));

    /* 文字颜色 - 深绿色文字 */
    --text-0: #1a2326;
    --text-1: #2e3c3f;
    --text-2: #4a5c5f;
    --text-3: #6a7d80;
    --text-4: #8a9da0;

    /* 主色调 - 深绿色系渐变（森林主题） */
    --primary-400: #388E3C;
    --primary-500: #2E7D32;
    --primary-600: #1B5E20;
    --primary-gradient: linear-gradient(135deg, #388E3C 0%, #2E7D32 50%, #1B5E20 100%);
    --primary-gradient-hover: linear-gradient(135deg, #2E7D32 0%, #1B5E20 50%, #0D4A13 100%);

    /* 强调色 - 黄绿色系渐变（新芽色） */
    --accent-500: #689F38;
    --accent-600: #558B2F;
    --accent-gradient: linear-gradient(135deg, #689F38 0%, #558B2F 50%, #33691E 100%);
    --accent-gradient-hover: linear-gradient(135deg, #558B2F 0%, #33691E 50%, #1B5E20 100%);

    /* 状态颜色 - 渐变效果 */
    --success: #388E3C;
    --success-gradient: linear-gradient(135deg, #388E3C 0%, #43A047 50%, #4CAF50 100%);
    --warning: #F57C00;
    --warning-gradient: linear-gradient(135deg, #F57C00 0%, #FF9800 50%, #FFB74D 100%);
    --error: #D32F2F;
    --error-gradient: linear-gradient(135deg, #D32F2F 0%, #E53935 50%, #EF5350 100%);
    --info: #0288D1;
    --info-gradient: linear-gradient(135deg, #0288D1 0%, #039BE5 50%, #03A9F4 100%);

    /* 代码高亮颜色 */
    --code-keyword: #388E3C;
    --code-string: #689F38;
    --code-number: #8BC34A;
    --code-comment: #6a7d80;
    --code-function: #558B2F;

    /* 兼容旧变量 */
    --bg-primary: var(--bg-2);
    --bg-secondary: var(--bg-1);
    --bg-tertiary: var(--bg-3);
    --bg-body: var(--bg-0);
    --bg-pane: var(--surface-0);
    --text-primary: var(--text-1);
    --text-secondary: var(--text-2);
    --text-muted: var(--text-3);
    --accent-blue: var(--primary-400);
    --accent-purple: var(--accent-500);
    --border: var(--border-base);
    --border-light: var(--border-subtle);
    --accent-bg: linear-gradient(135deg, rgba(56, 142, 60, 0.1), rgba(104, 159, 56, 0.1));
    --code-bg: linear-gradient(135deg, rgba(236, 255, 242, 0.9), rgba(232, 255, 235, 0.9));

    /* 界面尺寸 */
    --sidebar-width: 220px;
    --font-size: 15px;
    --border-radius: 10px;
    --border-radius-lg: 16px;

    /* 字体 */
    --font-ui: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    --font-read: 'Inter', 'Microsoft YaHei', sans-serif;
    --font-code: 'JetBrains Mono', Consolas, monospace;

    /* ==================== 🔴 滚动条样式变量（修复版） ==================== */
    /* 滚动条尺寸 */
    --scrollbar-width: 10px;
    --scrollbar-height: 10px;
    --scrollbar-thumb-radius: 6px;
    --scrollbar-track-radius: 10px;

    /* 滚动条颜色（用于Firefox，不支持渐变） */
    --scrollbar-thumb-color: var(--primary-500, #2E7D32);
    --scrollbar-thumb-hover-color: var(--primary-600, #1B5E20);
    --scrollbar-track-color: var(--surface-2, #ecfff2);

    /* 滚动条透明度 */
    --scrollbar-thumb-opacity: 0.8;
    --scrollbar-thumb-hover-opacity: 1;
    --scrollbar-track-opacity: 0.4;

    /* 滚动条渐变（用于WebKit浏览器） */
    --scrollbar-thumb-gradient: linear-gradient(135deg, var(--primary-500) 0%, var(--accent-500) 100%);
    --scrollbar-thumb-hover-gradient: linear-gradient(135deg, var(--primary-600) 0%, var(--accent-600) 100%);

    /* 滚动条阴影效果 */
    --scrollbar-thumb-shadow: 0 2px 10px rgba(56, 142, 60, 0.3), inset 0 1px 0 rgba(255, 255, 255, 0.2);
    --scrollbar-thumb-hover-shadow: 0 4px 20px rgba(56, 142, 60, 0.5), inset 0 1px 0 rgba(255, 255, 255, 0.3);

    /* 选中文本样式 */
    --selection-bg-color: linear-gradient(135deg, rgba(56, 142, 60, 0.3), rgba(104, 159, 56, 0.3));
    --selection-text-color: var(--text-0);
    --selection-border-width: 1px;
    --selection-border-color: var(--primary-400);

    /* 盒子内外边距 */
    --box-margin-top: 0px;
    --box-margin-right: 0px;
    --box-margin-bottom: 0px;
    --box-margin-left: 0px;
    --box-margin: var(--box-margin-top) var(--box-margin-right) var(--box-margin-bottom) var(--box-margin-left);
    --box-padding-top: 0px;
    --box-padding-right: 0px;
    --box-padding-bottom: 0px;
    --box-padding-left: 0px;
    --box-padding: var(--box-padding-top) var(--box-padding-right) var(--box-padding-bottom) var(--box-padding-left);

    /* 盒子边框 */
    --box-border-width: 0px;
    --box-border-style: solid;
    --box-border-color: transparent;
    --box-border: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-top: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-right: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-bottom: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-left: var(--box-border-width) var(--box-border-style) var(--box-border-color);

    /* 新增：阴影效果 - 森林柔和发光 */
    --shadow-primary: 0 4px 20px rgba(56, 142, 60, 0.2), 0 8px 30px rgba(104, 159, 56, 0.15);
    --shadow-accent: 0 4px 20px rgba(104, 159, 56, 0.2), 0 8px 30px rgba(56, 142, 60, 0.15);
    --shadow-elevated: 0 10px 40px rgba(0, 0, 0, 0.1), 0 0 20px rgba(56, 142, 60, 0.08);

    /* 新增：动画效果 */
    --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-bounce: 400ms cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

/* ==================== 🔴 滚动条样式修复（关键修复） ==================== */
/* Firefox滚动条 - 使用纯色（不支持渐变） */
* {
    scrollbar-width: thin !important;
    scrollbar-color: var(--scrollbar-thumb-color) var(--scrollbar-track-color) !important;
}

/* WebKit滚动条基础样式 */
*::-webkit-scrollbar,
::-webkit-scrollbar {
    width: var(--scrollbar-width, 10px) !important;
    height: var(--scrollbar-height, 10px) !important;
    background: transparent !important;
}

/* 滚动条滑块 - 修复渐变应用问题 */
*::-webkit-scrollbar-thumb,
::-webkit-scrollbar-thumb {
    /* 关键修复：使用background-image应用渐变，background-color作为fallback */
    background-image: var(--scrollbar-thumb-gradient) !important;
    background-color: var(--scrollbar-thumb-color) !important;
    /* 如果渐变未定义，使用纯色 */
    background: var(--scrollbar-thumb-gradient, var(--scrollbar-thumb-color)) !important;
    border-radius: var(--scrollbar-thumb-radius, 6px) !important;
    transition: all var(--transition-base, 200ms) cubic-bezier(0.4, 0, 0.2, 1) !important;
    opacity: var(--scrollbar-thumb-opacity, 0.9) !important;
    box-shadow: var(--scrollbar-thumb-shadow, 0 2px 10px rgba(255, 87, 51, 0.5)) !important;
    border: 2px solid transparent !important;
    background-clip: padding-box !important;
    position: relative !important;
    min-height: 20px !important;
    min-width: 20px !important;
}

/* 滚动条滑块悬停效果 */
*::-webkit-scrollbar-thumb:hover,
::-webkit-scrollbar-thumb:hover {
    background-image: var(--scrollbar-thumb-hover-gradient) !important;
    background-color: var(--scrollbar-thumb-hover-color) !important;
    background: var(--scrollbar-thumb-hover-gradient, var(--scrollbar-thumb-hover-color)) !important;
    box-shadow: var(--scrollbar-thumb-hover-shadow, 0 4px 20px rgba(255, 87, 51, 0.7)) !important;
    opacity: var(--scrollbar-thumb-hover-opacity, 1) !important;
    transform: scale(1.05) !important;
}

*::-webkit-scrollbar-thumb:active,
::-webkit-scrollbar-thumb:active {
    background-image: var(--scrollbar-thumb-hover-gradient) !important;
    background-color: var(--scrollbar-thumb-hover-color) !important;
    background: var(--scrollbar-thumb-hover-gradient, var(--scrollbar-thumb-hover-color)) !important;
    opacity: 1 !important;
    transform: scale(1.02) !important;
}

/* 滚动条轨道 */
*::-webkit-scrollbar-track,
::-webkit-scrollbar-track {
    background: var(--scrollbar-track-color) !important;
    border-radius: var(--scrollbar-track-radius, 10px) !important;
    opacity: var(--scrollbar-track-opacity, 0.4) !important;
    transition: opacity var(--transition-base, 200ms) ease !important;
    border: 1px solid var(--border-subtle, rgba(255, 87, 51, 0.2)) !important;
    margin: 4px !important;
}

*::-webkit-scrollbar-track:hover,
::-webkit-scrollbar-track:hover {
    opacity: calc(var(--scrollbar-track-opacity, 0.4) * 1.5) !important;
}

/* 滚动条角落 */
*::-webkit-scrollbar-corner,
::-webkit-scrollbar-corner {
    background: var(--scrollbar-track-color) !important;
    opacity: var(--scrollbar-track-opacity, 0.4) !important;
    border-radius: var(--scrollbar-track-radius, 10px) !important;
}

/* ==================== 基础样式 ==================== */
/* 应用主题变量到基本HTML元素 */

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-read);
    font-size: var(--font-size);
    line-height: 1.6;
    color: var(--text-primary);
    background: var(--bg-gradient-0);
    background-image: var(--bg-gradient-0);
    background-attachment: fixed;
    min-height: 100vh;
    overflow-x: hidden;
    transition: background-color var(--transition-base), color var(--transition-base), background-image var(--transition-base);
    position: relative;
}

body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: var(--bg-gradient-0);
    background-image: var(--bg-gradient-0);
    z-index: -1;
    opacity: 0.95;
}

/* 链接样式 */
a {
    color: var(--primary-400);
    text-decoration: none;
    transition: color var(--transition-fast);
    background: var(--primary-gradient);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

a:hover {
    background: var(--primary-gradient-hover);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    text-decoration: underline;
    filter: brightness(1.2);
}

/* 标题样式 */
h1, h2, h3, h4, h5, h6 {
    color: var(--text-0);
    font-weight: 600;
    line-height: 1.3;
    margin-top: 1.5em;
    margin-bottom: 0.5em;
}

h1 { 
    font-size: 2.5em;
    background: var(--primary-gradient);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

h2 { 
    font-size: 2em;
    background: var(--accent-gradient);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

h3 { 
    font-size: 1.5em;
    background: linear-gradient(135deg, var(--primary-400) 0%, var(--primary-500) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}
h4 { 
    font-size: 1.25em;
    background: linear-gradient(135deg, var(--primary-500) 0%, var(--accent-500) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}
h5 { 
    font-size: 1.125em;
    background: linear-gradient(135deg, var(--accent-500) 0%, var(--accent-600) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}
h6 { 
    font-size: 1em;
    background: linear-gradient(135deg, var(--primary-400) 0%, var(--accent-500) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

/* 代码样式 - 使用渐变背景 */
code {
    font-family: var(--font-code);
    font-size: 0.9em;
    background: var(--code-bg);
    background-image: var(--code-bg, var(--surface-gradient-1));
    color: var(--text-1);
    padding: 0.2em 0.4em;
    border-radius: var(--border-radius-sm, 4px);
    border: 1px solid var(--border-subtle);
    position: relative;
}

pre {
    font-family: var(--font-code);
    font-size: 0.9em;
    background: var(--code-bg);
    background-image: var(--code-bg, var(--surface-gradient-1));
    color: var(--text-1);
    padding: 1em;
    border-radius: var(--border-radius);
    border: 2px solid var(--border-base);
    overflow-x: auto;
    margin: 1em 0;
    line-height: 1.5;
    position: relative;
    box-shadow: var(--shadow-card);
}

pre::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--primary-gradient);
    border-radius: var(--border-radius) var(--border-radius) 0 0;
    opacity: 0.6;
}

pre code {
    background: transparent;
    padding: 0;
    border: none;
    font-size: inherit;
}

/* 选中文本样式 - 使用渐变背景 */
::selection {
    background: var(--selection-bg-color);
    background-image: var(--selection-bg-color, var(--primary-gradient));
    color: var(--selection-text-color);
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
}

::-moz-selection {
    background: var(--selection-bg-color);
    background-image: var(--selection-bg-color, var(--primary-gradient));
    color: var(--selection-text-color);
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
}

/* 聚焦状态 - 使用渐变外发光 */
:focus-visible {
    outline: none;
    border: 2px solid var(--primary-400);
    outline-offset: 2px;
    border-radius: var(--border-radius-sm, 4px);
    box-shadow: 0 0 0 2px var(--primary-400), 0 0 0 4px var(--accent-bg), 0 0 10px var(--primary-400), 0 0 20px var(--accent-500);
}

/* 按钮基础样式 - 使用渐变背景 */
button {
    font-family: var(--font-ui);
    font-size: var(--font-size);
    background: var(--surface-gradient-2);
    background-image: var(--surface-gradient-2);
    color: var(--text-primary);
    border: 2px solid transparent;
    border-radius: var(--border-radius);
    padding: 0.5em 1em;
    cursor: pointer;
    transition: all var(--transition-base);
    position: relative;
    overflow: hidden;
}

button::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: var(--primary-gradient);
    opacity: 0;
    transition: opacity var(--transition-base);
    z-index: -1;
}

button::after {
    content: '';
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    background: var(--border-base);
    background-image: var(--border-base, var(--primary-gradient));
    border-radius: var(--border-radius);
    z-index: -2;
    opacity: 0.5;
    transition: opacity var(--transition-base);
}

button:hover {
    background: var(--surface-gradient-3);
    background-image: var(--surface-gradient-3);
    transform: translateY(-1px);
    box-shadow: var(--shadow-primary);
}

button:hover::before {
    opacity: 0.15;
}

button:hover::after {
    opacity: 1;
}

button:active {
    transform: translateY(0);
    background: var(--primary-gradient);
    background-image: var(--primary-gradient);
}

button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    background: var(--surface-gradient-2);
    background-image: var(--surface-gradient-2);
}

/* 输入框样式 */
input, textarea, select {
    font-family: var(--font-ui);
    font-size: var(--font-size);
    background: var(--surface-gradient-0);
    color: var(--text-primary);
    border: 1px solid var(--border-base);
    border-radius: var(--border-radius);
    padding: 0.5em 0.75em;
    transition: all var(--transition-base);
}

input:focus, textarea:focus, select:focus {
    outline: none;
    border: 2px solid var(--primary-400);
    background: var(--surface-gradient-0);
    background-image: var(--surface-gradient-0);
    box-shadow: 0 0 0 2px var(--primary-400), 0 0 0 4px var(--accent-bg), 0 0 10px var(--primary-400), var(--shadow-primary);
}

/* 卡片样式 */
.card {
    background: var(--surface-gradient-0);
    border: 1px solid var(--border-base);
    border-radius: var(--border-radius-lg);
    padding: 1.5em;
    box-shadow: var(--shadow-elevated);
    transition: all var(--transition-base);
}

.card:hover {
    transform: translateY(-2px);
    box-shadow: var(--shadow-primary);
}

/* 表格样式 */
table {
    width: 100%;
    border-collapse: collapse;
    background: var(--surface-gradient-0);
    border-radius: var(--border-radius);
    overflow: hidden;
}

th, td {
    padding: 0.75em 1em;
    border-bottom: 2px solid transparent;
    background-image: linear-gradient(to bottom, transparent, var(--border-subtle));
    background-size: 100% 2px;
    background-repeat: no-repeat;
    background-position: bottom;
    text-align: left;
}

th {
    background: var(--surface-gradient-1);
    background-image: var(--surface-gradient-1, var(--primary-gradient));
    font-weight: 600;
    color: var(--text-0);
    position: relative;
}

th::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: var(--primary-gradient);
    opacity: 0.5;
}

tr:hover {
    background: var(--surface-gradient-1);
    background-image: linear-gradient(90deg, var(--surface-gradient-1), var(--accent-bg));
}

/* 列表样式 */
ul, ol {
    padding-left: 1.5em;
    margin: 1em 0;
}

li {
    margin: 0.5em 0;
}

/* 引用样式 - 使用渐变边框和背景 */
blockquote {
    border-left: 4px solid var(--primary-400);
    margin: 1.5em 0;
    padding-left: 1.5em;
    font-style: italic;
    color: var(--text-2);
    background: var(--accent-bg);
    background-image: var(--accent-bg, linear-gradient(135deg, rgba(255, 87, 51, 0.1), rgba(255, 138, 0, 0.1)));
    border-radius: 0 var(--border-radius) var(--border-radius) 0;
    padding: 1em;
    position: relative;
    overflow: hidden;
}

blockquote::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 4px;
    background: var(--primary-gradient);
    border-radius: 0 2px 2px 0;
}

/* 水平线 - 使用渐变 */
hr {
    border: none;
    height: 2px;
    background: var(--border-base);
    background-image: var(--border-base, var(--primary-gradient));
    margin: 2em 0;
    border-radius: 1px;
    opacity: 0.6;
}

/* 图片样式 - 使用渐变边框 */
img {
    max-width: 100%;
    height: auto;
    border-radius: var(--border-radius);
    border: 2px solid var(--border-subtle);
    background: var(--surface-gradient-0);
    padding: 2px;
    box-shadow: var(--shadow-card);
    transition: all var(--transition-base);
    position: relative;
}

img::before {
    content: '';
    position: absolute;
    top: -2px;
    left: -2px;
    right: -2px;
    bottom: -2px;
    background: var(--border-base);
    background-image: var(--border-base, var(--primary-gradient));
    border-radius: var(--border-radius);
    z-index: -1;
    opacity: 0.5;
}

img:hover {
    border-color: var(--primary-400);
    box-shadow: var(--shadow-primary);
    transform: translateY(-2px);
}

img:hover::before {
    opacity: 1;
}

/* 工具类 */
.text-center { text-align: center; }
.text-right { text-align: right; }
.text-left { text-align: left; }

.mt-1 { margin-top: 0.25em; }
.mt-2 { margin-top: 0.5em; }
.mt-3 { margin-top: 1em; }
.mt-4 { margin-top: 1.5em; }
.mt-5 { margin-top: 2em; }

.mb-1 { margin-bottom: 0.25em; }
.mb-2 { margin-bottom: 0.5em; }
.mb-3 { margin-bottom: 1em; }
.mb-4 { margin-bottom: 1.5em; }
.mb-5 { margin-bottom: 2em; }

.p-1 { padding: 0.25em; }
.p-2 { padding: 0.5em; }
.p-3 { padding: 1em; }
.p-4 { padding: 1.5em; }
.p-5 { padding: 2em; }

.d-flex { display: flex; }
.flex-column { flex-direction: column; }
.justify-center { justify-content: center; }
.align-center { align-items: center; }
.flex-wrap { flex-wrap: wrap; }

/* 状态颜色类 */
.text-success { color: var(--success); }
.text-warning { color: var(--warning); }
.text-error { color: var(--error); }
.text-info { color: var(--info); }

.bg-success { background: var(--success-gradient); }
.bg-warning { background: var(--warning-gradient); }
.bg-error { background: var(--error-gradient); }
.bg-info { background: var(--info-gradient); }

/* 边框颜色类 - 使用渐变外发光效果 */
.border-success { 
    border: 2px solid var(--success);
    box-shadow: 0 0 0 2px var(--success), 0 0 10px var(--success);
}
.border-warning { 
    border: 2px solid var(--warning);
    box-shadow: 0 0 0 2px var(--warning), 0 0 10px var(--warning);
}
.border-error { 
    border: 2px solid var(--error);
    box-shadow: 0 0 0 2px var(--error), 0 0 10px var(--error);
}
.border-info { 
    border: 2px solid var(--info);
    box-shadow: 0 0 0 2px var(--info), 0 0 10px var(--info);
}

/* 圆角类 */
.rounded { border-radius: var(--border-radius); }
.rounded-lg { border-radius: var(--border-radius-lg); }
.rounded-full { border-radius: 9999px; }

/* 阴影类 */
.shadow-sm { box-shadow: var(--shadow-primary); }
.shadow-md { box-shadow: var(--shadow-accent); }
.shadow-lg { box-shadow: var(--shadow-elevated); }

/* 渐变背景类 */
.bg-gradient-primary { background: var(--primary-gradient); }
.bg-gradient-accent { background: var(--accent-gradient); }
.bg-gradient-success { background: var(--success-gradient); }

/* 渐变文字类 */
.text-gradient-primary {
    background: var(--primary-gradient);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.text-gradient-accent {
    background: var(--accent-gradient);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

/* 动画类 */
.animate-pulse {
    animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.5; }
}

.animate-spin {
    animation: spin 1s linear infinite;
}

@keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

/* 过渡类 */
.transition-all { transition: all var(--transition-base); }
.transition-colors { transition: color var(--transition-base), background-color var(--transition-base); }
.transition-transform { transition: transform var(--transition-base); }

/* 隐藏类 */
.hidden { display: none; }
.visible { display: block; }
.invisible { visibility: hidden; }

/* 响应式设计 */
@media (max-width: 768px) {
    :root {
        --font-size: 14px;
        --sidebar-width: 200px;
    }

    body {
        font-size: var(--font-size);
    }

    .card {
        padding: 1em;
    }

    table {
        display: block;
        overflow-x: auto;
    }
}

@media (max-width: 480px) {
    :root {
        --font-size: 13px;
        --sidebar-width: 180px;
    }

    h1 { font-size: 2em; }
    h2 { font-size: 1.5em; }
    h3 { font-size: 1.25em; }

    .card {
        padding: 0.75em;
    }
}

/* 打印样式 */
@media print {
    :root {
        --bg-gradient-0: #ffffff;
        --text-primary: #000000;
        --text-0: #000000;
        --text-1: #333333;
        --text-2: #666666;
    }

    body {
        background: white;
        color: black;
        font-size: 12pt;
    }

    a {
        color: black;
        text-decoration: underline;
    }

    .no-print {
        display: none !important;
    }

    .card {
        border: 1px solid #ccc;
        box-shadow: none;
    }

    ::-webkit-scrollbar {
        display: none;
    }
}

/* 主题切换动画 */
.theme-transition * {
    transition: background-color var(--transition-slow), 
                color var(--transition-slow),
                border-color var(--transition-slow),
                box-shadow var(--transition-slow);
}

/* 暗色模式媒体查询支持 */
/* 注意：当没有设置 data-theme 时，系统会根据 prefers-color-scheme 自动选择 */
/* 所有变量已在 :root 和 [data-theme="light"] 中定义 */

/* 高对比度模式 */
@media (prefers-contrast: high) {
    :root {
        --text-0: #ffffff;
        --text-1: #ffffff;
        --text-2: #e0e0e0;
        --text-3: #c0c0c0;
        --border-base: rgba(255, 255, 255, 0.5);
        --border-strong: rgba(255, 255, 255, 0.8);
    }

    [data-theme="light"] {
        --text-0: #000000;
        --text-1: #000000;
        --text-2: #333333;
        --text-3: #666666;
        --border-base: rgba(0, 0, 0, 0.5);
        --border-strong: rgba(0, 0, 0, 0.8);
    }
}

/* 减少动画模式 */
@media (prefers-reduced-motion: reduce) {
    :root {
        --transition-fast: 0ms;
        --transition-base: 0ms;
        --transition-slow: 0ms;
        --transition-bounce: 0ms;
    }

    * {
        animation-duration: 0ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0ms !important;
    }
}

/* ==================== 熔岩火焰主题 ==================== */
/* 包含日间和夜间两种模式，根据 data-theme 属性切换 */
/* 设计特点：暖色调渐变、强烈对比、火焰效果 */

/* ==================== ⚠️ 重要提示：渐变背景设计 ⚠️ ==================== */
/*
 * 🔴 渐变背景颜色变量（必须修改）：
 * 这些变量控制整个应用的渐变背景颜色，是主题的核心！
 * 请根据你的设计需求修改以下变量：
 *
 * --bg-gradient-0 到 --bg-gradient-4: 基础渐变背景色层次
 * --surface-gradient-0 到 --surface-gradient-3: 表面渐变颜色
 *
 * 建议：使用互补色或类似色调创建和谐渐变
 */

/* ==================== 夜间模式（默认）- 熔岩火焰 ==================== */
:root {
  /* ==================== 🔴 渐变背景颜色（必须修改） ==================== */
  /* 基础渐变背景色 - 深红到深橙渐变（熔岩效果） */
  --bg-gradient-0: linear-gradient(135deg, #0a0a0a 0%, #1a0a0a 50%, #2a0a0a 100%); /* 🔴 最深层渐变背景 */
  --bg-gradient-1: linear-gradient(135deg, #1a0a0a 0%, #2a0a0a 50%, #3a0a0a 100%); /* 🔴 主渐变背景 */
  --bg-gradient-2: linear-gradient(135deg, #2a0a0a 0%, #3a0a0a 50%, #4a0a0a 100%); /* 🔴 次要渐变背景 */
  --bg-gradient-3: linear-gradient(135deg, #3a0a0a 0%, #4a0a0a 50%, #5a0a0a 100%); /* 🔴 三级渐变背景 */
  --bg-gradient-4: linear-gradient(135deg, #4a0a0a 0%, #5a0a0a 50%, #6a0a0a 100%); /* 🔴 四级渐变背景 */

  /* 表面渐变颜色 - 用于卡片、面板、按钮等（火焰表面效果） */
  --surface-gradient-0: linear-gradient(145deg, #2a0a0a 0%, #3a0a0a 100%); /* 🔴 表面0渐变 */
  --surface-gradient-1: linear-gradient(145deg, #3a0a0a 0%, #4a0a0a 100%); /* 🔴 表面1渐变 */
  --surface-gradient-2: linear-gradient(145deg, #4a0a0a 0%, #5a0a0a 100%); /* 🔴 表面2渐变（按钮默认背景） */
  --surface-gradient-3: linear-gradient(145deg, #5a0a0a 0%, #6a0a0a 100%); /* 🔴 表面3渐变（按钮hover背景） */

  /* 兼容纯色变量（用于不支持渐变的元素） */
  --bg-0: #0a0a0a;
  --bg-1: #1a0a0a;
  --bg-2: #2a0a0a;
  --bg-3: #3a0a0a;
  --bg-4: #4a0a0a;

  --surface-0: #2a0a0a;
  --surface-1: #3a0a0a;
  --surface-2: #4a0a0a;
  --surface-3: #5a0a0a;

  /* 边框颜色 - 火焰色边框 */
  --border-subtle: rgba(255, 87, 51, 0.2);
  --border-base: linear-gradient(90deg, rgba(255, 87, 51, 0.4), rgba(255, 138, 0, 0.4));
  --border-strong: linear-gradient(90deg, rgba(255, 87, 51, 0.6), rgba(255, 138, 0, 0.6));
  --border-emphasis: linear-gradient(90deg, rgba(255, 87, 51, 0.8), rgba(255, 138, 0, 0.8));

  /* 文字颜色 - 亮色文字确保可读性 */
  --text-0: #ffffff;
  --text-1: #ffeded;
  --text-2: #ffcccc;
  --text-3: #ffaaaa;
  --text-4: #ff8888;

  /* 主色调 - 橙色系渐变（火焰核心色） */
  --primary-400: #ff5733;
  --primary-500: #ff8a00;
  --primary-600: #ffa500;
  --primary-gradient: linear-gradient(135deg, #ff5733 0%, #ff8a00 50%, #ffa500 100%);
  --primary-gradient-hover: linear-gradient(135deg, #ff8a00 0%, #ffa500 50%, #ffc107 100%);

  /* 强调色 - 红色系渐变（火焰外围色） */
  --accent-500: #ff3333;
  --accent-600: #ff5555;
  --accent-gradient: linear-gradient(135deg, #ff3333 0%, #ff5555 50%, #ff7777 100%);
  --accent-gradient-hover: linear-gradient(135deg, #ff5555 0%, #ff7777 50%, #ff9999 100%);

  /* 状态颜色 - 渐变效果 */
  --success: #4CAF50;
  --success-gradient: linear-gradient(135deg, #4CAF50 0%, #66BB6A 50%, #81C784 100%);

  --warning: #FF9800;
  --warning-gradient: linear-gradient(135deg, #FF9800 0%, #FFB74D 50%, #FFCC80 100%);

  --error: #F44336;
  --error-gradient: linear-gradient(135deg, #F44336 0%, #EF5350 50%, #E57373 100%);

  --info: #2196F3;
  --info-gradient: linear-gradient(135deg, #2196F3 0%, #42A5F5 50%, #64B5F6 100%);

  /* 代码高亮颜色 */
  --code-keyword: #ff5733;
  --code-string: #ff8a00;
  --code-number: #ffa500;
  --code-comment: #ff8888;
  --code-function: #ff3333;

  /* 兼容旧变量 */
  --bg-primary: var(--bg-1);
  --bg-secondary: var(--bg-2);
  --bg-tertiary: var(--bg-3);
  --bg-body: var(--bg-0);
  --bg-pane: var(--surface-0);

  --text-primary: var(--text-1);
  --text-secondary: var(--text-2);
  --text-muted: var(--text-3);

  --accent-blue: var(--primary-400);
  --accent-purple: var(--accent-500);

  --border: var(--border-base);
  --border-light: var(--border-subtle);

  --accent-bg: linear-gradient(135deg, rgba(255, 87, 51, 0.15), rgba(255, 138, 0, 0.15));
  --code-bg: linear-gradient(135deg, rgba(42, 10, 10, 0.9), rgba(58, 10, 10, 0.9));

  /* 界面尺寸 */
  --sidebar-width: 220px;
  --font-size: 15px;
  --border-radius: 10px;
  --border-radius-lg: 16px;

  /* 字体 */
  --font-ui: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-read: 'Inter', 'Microsoft YaHei', sans-serif;
  --font-code: 'JetBrains Mono', Consolas, monospace;

  /* 滚动条样式变量 */
  --scrollbar-width: 10px;
  --scrollbar-height: 10px;
  --scrollbar-thumb-radius: 6px;
  --scrollbar-track-radius: 10px;

  --scrollbar-thumb-color: var(--primary-gradient);
  --scrollbar-thumb-hover-color: var(--primary-gradient-hover);
  --scrollbar-track-color: var(--bg-gradient-2);

  --scrollbar-thumb-opacity: 0.9;
  --scrollbar-thumb-hover-opacity: 1;
  --scrollbar-track-opacity: 0.4;

  --scrollbar-thumb-shadow: 0 2px 10px rgba(255, 87, 51, 0.5), inset 0 1px 0 rgba(255, 255, 255, 0.2);
  --scrollbar-thumb-hover-shadow: 0 4px 20px rgba(255, 87, 51, 0.7), inset 0 1px 0 rgba(255, 255, 255, 0.3);

  --scrollbar-thumb-gradient: var(--primary-gradient);
  --scrollbar-thumb-hover-gradient: var(--primary-gradient-hover);

  /* 选中文本样式 */
  --selection-bg-color: linear-gradient(135deg, rgba(255, 87, 51, 0.4), rgba(255, 138, 0, 0.4));
  --selection-text-color: var(--text-0);
  --selection-border-width: 1px;
  --selection-border-color: var(--primary-400);

  /* 盒子内外边距 */
  --box-margin-top: 0px;
  --box-margin-right: 0px;
  --box-margin-bottom: 0px;
  --box-margin-left: 0px;
  --box-margin: var(--box-margin-top) var(--box-margin-right) var(--box-margin-bottom) var(--box-margin-left);

  --box-padding-top: 0px;
  --box-padding-right: 0px;
  --box-padding-bottom: 0px;
  --box-padding-left: 0px;
  --box-padding: var(--box-padding-top) var(--box-padding-right) var(--box-padding-bottom) var(--box-padding-left);

  /* 盒子边框 */
  --box-border-width: 0px;
  --box-border-style: solid;
  --box-border-color: transparent;
  --box-border: var(--box-border-width) var(--box-border-style) var(--box-border-color);

  --box-border-top: var(--box-border-width) var(--box-border-style) var(--box-border-color);
  --box-border-right: var(--box-border-width) var(--box-border-style) var(--box-border-color);
  --box-border-bottom: var(--box-border-width) var(--box-border-style) var(--box-border-color);
  --box-border-left: var(--box-border-width) var(--box-border-style) var(--box-border-color);

  /* 新增：阴影效果 - 火焰发光 */
  --shadow-primary: 0 4px 20px rgba(255, 87, 51, 0.4), 0 8px 30px rgba(255, 138, 0, 0.3);
  --shadow-accent: 0 4px 20px rgba(255, 51, 51, 0.4), 0 8px 30px rgba(255, 87, 51, 0.3);
  --shadow-elevated: 0 10px 40px rgba(255, 0, 0, 0.3), 0 0 20px rgba(255, 87, 51, 0.2);

  /* 新增：动画效果 */
  --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-bounce: 400ms cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

/* ==================== 日间模式 - 森林绿意（渐变加强版） ==================== */
[data-theme="light"] {
  /* ==================== 🔴 渐变背景颜色（加强对比） ==================== */
  /* 基础渐变背景色 - 由偏黄的晨光到偏绿的树林，肉眼清晰可见的渐变 */
  --bg-gradient-0: linear-gradient(135deg, #f0fff4 0%, #c8f7d4 45%, #e0ffe0 100%);  /* 页面整体背景 */
  --bg-gradient-1: linear-gradient(135deg, #ffffff 0%, #e6fffa 50%, #f4ffde 100%);
  --bg-gradient-2: linear-gradient(135deg, #e8fff4 0%, #c0f2d6 50%, #d9ffea 100%);
  --bg-gradient-3: linear-gradient(135deg, #d9ffea 0%, #b9f6ca 50%, #ccff90 100%);
  --bg-gradient-4: linear-gradient(135deg, #ccff90 0%, #a5d6a7 50%, #81c784 100%);

  /* 表面渐变颜色 - 卡片/面板/按钮的绿色渐变更明显 */
  --surface-gradient-0: linear-gradient(145deg, #ffffff 0%, #e8fff4 100%);
  --surface-gradient-1: linear-gradient(145deg, #e8fff4 0%, #d2f9e0 100%);
  --surface-gradient-2: linear-gradient(145deg, #d2f9e0 0%, #b9f6ca 100%); /* 按钮默认 */
  --surface-gradient-3: linear-gradient(145deg, #b9f6ca 0%, #a5d6a7 100%); /* 按钮 hover */

  /* 兼容纯色变量（用于不支持渐变的元素） */
  --bg-0: #e8fff4;
  --bg-1: #ffffff;
  --bg-2: #d2f9e0;
  --bg-3: #b9f6ca;
  --bg-4: #a5d6a7;

  --surface-0: #ffffff;
  --surface-1: #e8fff4;
  --surface-2: #d2f9e0;
  --surface-3: #b9f6ca;

  /* 边框颜色 - 绿叶色边框（稍微加深，轮廓更清晰） */
  --border-subtle: rgba(56, 142, 60, 0.2);
  --border-base: linear-gradient(90deg, rgba(56, 142, 60, 0.35), rgba(104, 159, 56, 0.35));
  --border-strong: linear-gradient(90deg, rgba(56, 142, 60, 0.5), rgba(104, 159, 56, 0.5));
  --border-emphasis: linear-gradient(90deg, rgba(56, 142, 60, 0.7), rgba(104, 159, 56, 0.7));

  /* 文字颜色 - 深绿色文字 */
  --text-0: #1a2326;
  --text-1: #2e3c3f;
  --text-2: #4a5c5f;
  --text-3: #6a7d80;
  --text-4: #8a9da0;

  /* 主色调 - 深绿色系渐变（森林主题） */
  --primary-400: #388E3C;
  --primary-500: #2E7D32;
  --primary-600: #1B5E20;
  --primary-gradient: linear-gradient(135deg, #43A047 0%, #2E7D32 45%, #1B5E20 100%);
  --primary-gradient-hover: linear-gradient(135deg, #66BB6A 0%, #2E7D32 45%, #0D4A13 100%);

  /* 强调色 - 黄绿色系渐变（新芽色） */
  --accent-500: #689F38;
  --accent-600: #558B2F;
  --accent-gradient: linear-gradient(135deg, #AED581 0%, #689F38 45%, #33691E 100%);
  --accent-gradient-hover: linear-gradient(135deg, #C5E1A5 0%, #558B2F 45%, #1B5E20 100%);

  /* 状态颜色 - 渐变效果（保持与熔岩类似的强度） */
  --success: #388E3C;
  --success-gradient: linear-gradient(135deg, #388E3C 0%, #43A047 50%, #4CAF50 100%);
  --warning: #F57C00;
  --warning-gradient: linear-gradient(135deg, #F57C00 0%, #FF9800 50%, #FFB74D 100%);
  --error: #D32F2F;
  --error-gradient: linear-gradient(135deg, #D32F2F 0%, #E53935 50%, #EF5350 100%);
  --info: #0288D1;
  --info-gradient: linear-gradient(135deg, #0288D1 0%, #039BE5 50%, #03A9F4 100%);

  /* 代码高亮颜色 */
  --code-keyword: #388E3C;
  --code-string: #689F38;
  --code-number: #8BC34A;
  --code-comment: #6a7d80;
  --code-function: #558B2F;

  /* 兼容旧变量 */
  --bg-primary: var(--bg-2);
  --bg-secondary: var(--bg-1);
  --bg-tertiary: var(--bg-3);
  --bg-body: var(--bg-0);
  --bg-pane: var(--surface-0);

  --text-primary: var(--text-1);
  --text-secondary: var(--text-2);
  --text-muted: var(--text-3);

  --accent-blue: var(--primary-400);
  --accent-purple: var(--accent-500);

  --border: var(--border-base);
  --border-light: var(--border-subtle);

  /* 森林版的柔和绿色高亮背景（引用、提示块等用） */
  --accent-bg: linear-gradient(
    135deg,
    rgba(200, 245, 210, 0.8),
    rgba(178, 235, 242, 0.7)
  );

  --code-bg: linear-gradient(
    135deg,
    rgba(232, 255, 244, 0.95),
    rgba(208, 242, 222, 0.95)
  );

  /* 界面尺寸 */
  --sidebar-width: 220px;
  --font-size: 15px;
  --border-radius: 10px;
  --border-radius-lg: 16px;

  /* 字体 */
  --font-ui: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --font-read: 'Inter', 'Microsoft YaHei', sans-serif;
  --font-code: 'JetBrains Mono', Consolas, monospace;

  /* ==================== 🔴 滚动条样式变量（绿意渐变） ==================== */
  /* 滚动条尺寸 */
  --scrollbar-width: 10px;
  --scrollbar-height: 10px;
  --scrollbar-thumb-radius: 6px;
  --scrollbar-track-radius: 10px;

  /* 滚动条颜色（用于Firefox，不支持渐变） */
  --scrollbar-thumb-color: var(--primary-500, #2E7D32);
  --scrollbar-thumb-hover-color: var(--primary-600, #1B5E20);
  --scrollbar-track-color: rgba(210, 249, 224, 0.8);

  /* 滚动条透明度 */
  --scrollbar-thumb-opacity: 0.85;
  --scrollbar-thumb-hover-opacity: 1;
  --scrollbar-track-opacity: 0.45;

  /* 滚动条渐变（用于WebKit浏览器） */
  --scrollbar-thumb-gradient: linear-gradient(135deg, #43A047 0%, #66BB6A 45%, #8BC34A 100%);
  --scrollbar-thumb-hover-gradient: linear-gradient(135deg, #2E7D32 0%, #388E3C 45%, #689F38 100%);

  /* 滚动条阴影效果 */
  --scrollbar-thumb-shadow: 0 2px 10px rgba(56, 142, 60, 0.35), inset 0 1px 0 rgba(255, 255, 255, 0.25);
  --scrollbar-thumb-hover-shadow: 0 4px 20px rgba(56, 142, 60, 0.55), inset 0 1px 0 rgba(255, 255, 255, 0.35);

  /* 选中文本样式（从浅绿到浅黄的渐变条） */
  --selection-bg-color: linear-gradient(135deg, rgba(76, 175, 80, 0.35), rgba(205, 220, 57, 0.35));
  --selection-text-color: var(--text-0);
  --selection-border-width: 1px;
  --selection-border-color: var(--primary-400);

  /* 盒子内外边距 */
  --box-margin-top: 0px;
  --box-margin-right: 0px;
  --box-margin-bottom: 0px;
  --box-margin-left: 0px;
  --box-margin: var(--box-margin-top) var(--box-margin-right) var(--box-margin-bottom) var(--box-margin-left);

  --box-padding-top: 0px;
  --box-padding-right: 0px;
  --box-padding-bottom: 0px;
  --box-padding-left: 0px;
  --box-padding: var(--box-padding-top) var(--box-padding-right) var(--box-padding-bottom) var(--box-padding-left);

  /* 盒子边框 */
  --box-border-width: 0px;
  --box-border-style: solid;
  --box-border-color: transparent;
  --box-border: var(--box-border-width) var(--box-border-style) var(--box-border-color);

  --box-border-top: var(--box-border-width) var(--box-border-style) var(--box-border-color);
  --box-border-right: var(--box-border-width) var(--box-border-style) var(--box-border-color);
  --box-border-bottom: var(--box-border-width) var(--box-border-style) var(--box-border-color);
  --box-border-left: var(--box-border-width) var(--box-border-style) var(--box-border-color);

  /* 新增：阴影效果 - 森林柔和发光 */
  --shadow-primary: 0 4px 20px rgba(56, 142, 60, 0.25), 0 8px 30px rgba(104, 159, 56, 0.2);
  --shadow-accent: 0 4px 20px rgba(104, 159, 56, 0.25), 0 8px 30px rgba(56, 142, 60, 0.2);
  --shadow-elevated: 0 10px 40px rgba(0, 0, 0, 0.08), 0 0 20px rgba(56, 142, 60, 0.12);

  /* 新增：动画效果 */
  --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
  --transition-bounce: 400ms cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

/* ==================== 🔴 通用滚动条样式修复（关键修复） ==================== */
/* Firefox滚动条 - 使用纯色（不支持渐变） */
* {
  scrollbar-width: thin !important;
  scrollbar-color: var(--scrollbar-thumb-color) var(--scrollbar-track-color) !important;
}

/* WebKit滚动条基础样式 */
*::-webkit-scrollbar,
::-webkit-scrollbar {
  width: var(--scrollbar-width, 10px) !important;
  height: var(--scrollbar-height, 10px) !important;
  background: transparent !important;
}

/* 滚动条滑块 - 修复渐变应用问题 */
*::-webkit-scrollbar-thumb,
::-webkit-scrollbar-thumb {
  /* 关键修复：使用background-image应用渐变，background-color作为fallback */
  background-image: var(--scrollbar-thumb-gradient) !important;
  background-color: var(--scrollbar-thumb-color) !important;
  /* 如果渐变未定义，使用纯色 */
  background: var(
    --scrollbar-thumb-gradient,
    var(--scrollbar-thumb-color)
  ) !important;

  border-radius: var(--scrollbar-thumb-radius, 6px) !important;
  transition: all var(--transition-base, 200ms) cubic-bezier(0.4, 0, 0.2, 1) !important;
  opacity: var(--scrollbar-thumb-opacity, 0.9) !important;
  box-shadow: var(
    --scrollbar-thumb-shadow,
    0 2px 10px rgba(255, 87, 51, 0.5)
  ) !important;
  border: 2px solid transparent !important;
  background-clip: padding-box !important;
  position: relative !important;
  min-height: 20px !important;
  min-width: 20px !important;
}

/* 滚动条滑块悬停效果 */
*::-webkit-scrollbar-thumb:hover,
::-webkit-scrollbar-thumb:hover {
  background-image: var(--scrollbar-thumb-hover-gradient) !important;
  background-color: var(--scrollbar-thumb-hover-color) !important;
  background: var(
    --scrollbar-thumb-hover-gradient,
    var(--scrollbar-thumb-hover-color)
  ) !important;
  box-shadow: var(
    --scrollbar-thumb-hover-shadow,
    0 4px 20px rgba(255, 87, 51, 0.7)
  ) !important;
  opacity: var(--scrollbar-thumb-hover-opacity, 1) !important;
  transform: scale(1.05) !important;
}

*::-webkit-scrollbar-thumb:active,
::-webkit-scrollbar-thumb:active {
  background-image: var(--scrollbar-thumb-hover-gradient) !important;
  background-color: var(--scrollbar-thumb-hover-color) !important;
  background: var(
    --scrollbar-thumb-hover-gradient,
    var(--scrollbar-thumb-hover-color)
  ) !important;
  opacity: 1 !important;
  transform: scale(1.02) !important;
}

/* 滚动条轨道 */
*::-webkit-scrollbar-track,
::-webkit-scrollbar-track {
  background: var(--scrollbar-track-color) !important;
  border-radius: var(--scrollbar-track-radius, 10px) !important;
  opacity: var(--scrollbar-track-opacity, 0.4) !important;
  transition: opacity var(--transition-base, 200ms) ease !important;
  border: 1px solid var(--border-subtle, rgba(255, 87, 51, 0.2)) !important;
  margin: 4px !important;
}

*::-webkit-scrollbar-track:hover,
::-webkit-scrollbar-track:hover {
  opacity: calc(var(--scrollbar-track-opacity, 0.4) * 1.5) !important;
}

/* 滚动条角落 */
*::-webkit-scrollbar-corner,
::-webkit-scrollbar-corner {
  background: var(--scrollbar-track-color) !important;
  opacity: var(--scrollbar-track-opacity, 0.4) !important;
  border-radius: var(--scrollbar-track-radius, 10px) !important;
}

/* ==================== 基础样式 ==================== */

/* 应用主题变量到基本HTML元素 */
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-read);
  font-size: var(--font-size);
  line-height: 1.6;
  color: var(--text-primary);
  background: var(--bg-gradient-0);
  background-image: var(--bg-gradient-0);
  background-attachment: fixed;
  min-height: 100vh;
  overflow-x: hidden;
  transition: background-color var(--transition-base), color var(--transition-base),
    background-image var(--transition-base);
  position: relative;
}

body::before {
  content: '';
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--bg-gradient-0);
  background-image: var(--bg-gradient-0);
  z-index: -1;
  opacity: 0.95;
}

/* 链接样式 */
a {
  color: var(--primary-400);
  text-decoration: none;
  transition: color var(--transition-fast);
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

a:hover {
  background: var(--primary-gradient-hover);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-decoration: underline;
  filter: brightness(1.2);
}

/* 标题样式 */
h1,
h2,
h3,
h4,
h5,
h6 {
  color: var(--text-0);
  font-weight: 600;
  line-height: 1.3;
  margin-top: 1.5em;
  margin-bottom: 0.5em;
}

h1 {
  font-size: 2.5em;
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

h2 {
  font-size: 2em;
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

h3 {
  font-size: 1.5em;
  background: linear-gradient(135deg, var(--primary-400) 0%, var(--primary-500) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

h4 {
  font-size: 1.25em;
  background: linear-gradient(135deg, var(--primary-500) 0%, var(--accent-500) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

h5 {
  font-size: 1.125em;
  background: linear-gradient(135deg, var(--accent-500) 0%, var(--accent-600) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

h6 {
  font-size: 1em;
  background: linear-gradient(135deg, var(--primary-400) 0%, var(--accent-500) 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* 代码样式 - 使用渐变背景 */
code {
  font-family: var(--font-code);
  font-size: 0.9em;
  background: var(--code-bg);
  background-image: var(--code-bg, var(--surface-gradient-1));
  color: var(--text-1);
  padding: 0.2em 0.4em;
  border-radius: var(--border-radius-sm, 4px);
  border: 1px solid var(--border-subtle);
  position: relative;
}

pre {
  font-family: var(--font-code);
  font-size: 0.9em;
  background: var(--code-bg);
  background-image: var(--code-bg, var(--surface-gradient-1));
  color: var(--text-1);
  padding: 1em;
  border-radius: var(--border-radius);
  border: 2px solid var(--border-base);
  overflow-x: auto;
  margin: 1em 0;
  line-height: 1.5;
  position: relative;
  box-shadow: var(--shadow-card);
}

pre::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--primary-gradient);
  border-radius: var(--border-radius) var(--border-radius) 0 0;
  opacity: 0.6;
}

pre code {
  background: transparent;
  padding: 0;
  border: none;
  font-size: inherit;
}

/* 选中文本样式 - 使用渐变背景 */
::selection {
  background: var(--selection-bg-color);
  background-image: var(--selection-bg-color, var(--primary-gradient));
  color: var(--selection-text-color);
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
}

::-moz-selection {
  background: var(--selection-bg-color);
  background-image: var(--selection-bg-color, var(--primary-gradient));
  color: var(--selection-text-color);
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
}

/* 聚焦状态 - 使用渐变外发光 */
:focus-visible {
  outline: none;
  border: 2px solid var(--primary-400);
  outline-offset: 2px;
  border-radius: var(--border-radius-sm, 4px);
  box-shadow: 0 0 0 2px var(--primary-400), 0 0 0 4px var(--accent-bg),
    0 0 10px var(--primary-400), 0 0 20px var(--accent-500);
}

/* 按钮基础样式 - 使用渐变背景 */
button {
  font-family: var(--font-ui);
  font-size: var(--font-size);
  background: var(--surface-gradient-2);
  background-image: var(--surface-gradient-2);
  color: var(--text-primary);
  border: 2px solid transparent;
  border-radius: var(--border-radius);
  padding: 0.5em 1em;
  cursor: pointer;
  transition: all var(--transition-base);
  position: relative;
  overflow: hidden;
}

button::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: var(--primary-gradient);
  opacity: 0;
  transition: opacity var(--transition-base);
  z-index: -1;
}

button::after {
  content: '';
  position: absolute;
  top: -2px;
  left: -2px;
  right: -2px;
  bottom: -2px;
  background: var(--border-base);
  background-image: var(--border-base, var(--primary-gradient));
  border-radius: var(--border-radius);
  z-index: -2;
  opacity: 0.5;
  transition: opacity var(--transition-base);
}

button:hover {
  background: var(--surface-gradient-3);
  background-image: var(--surface-gradient-3);
  transform: translateY(-1px);
  box-shadow: var(--shadow-primary);
}

button:hover::before {
  opacity: 0.15;
}

button:hover::after {
  opacity: 1;
}

button:active {
  transform: translateY(0);
  background: var(--primary-gradient);
  background-image: var(--primary-gradient);
}

button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  background: var(--surface-gradient-2);
  background-image: var(--surface-gradient-2);
}

/* 输入框样式 */
input,
textarea,
select {
  font-family: var(--font-ui);
  font-size: var(--font-size);
  background: var(--surface-gradient-0);
  color: var(--text-primary);
  border: 1px solid var(--border-base);
  border-radius: var(--border-radius);
  padding: 0.5em 0.75em;
  transition: all var(--transition-base);
}

input:focus,
textarea:focus,
select:focus {
  outline: none;
  border: 2px solid var(--primary-400);
  background: var(--surface-gradient-0);
  background-image: var(--surface-gradient-0);
  box-shadow: 0 0 0 2px var(--primary-400), 0 0 0 4px var(--accent-bg),
    0 0 10px var(--primary-400), var(--shadow-primary);
}

/* 卡片样式 */
.card {
  background: var(--surface-gradient-0);
  border: 1px solid var(--border-base);
  border-radius: var(--border-radius-lg);
  padding: 1.5em;
  box-shadow: var(--shadow-elevated);
  transition: all var(--transition-base);
}

.card:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-primary);
}

/* 表格样式 */
table {
  width: 100%;
  border-collapse: collapse;
  background: var(--surface-gradient-0);
  border-radius: var(--border-radius);
  overflow: hidden;
}

th,
td {
  padding: 0.75em 1em;
  border-bottom: 2px solid transparent;
  background-image: linear-gradient(to bottom, transparent, var(--border-subtle));
  background-size: 100% 2px;
  background-repeat: no-repeat;
  background-position: bottom;
  text-align: left;
}

th {
  background: var(--surface-gradient-1);
  background-image: var(--surface-gradient-1, var(--primary-gradient));
  font-weight: 600;
  color: var(--text-0);
  position: relative;
}

th::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: var(--primary-gradient);
  opacity: 0.5;
}

tr:hover {
  background: var(--surface-gradient-1);
  background-image: linear-gradient(90deg, var(--surface-gradient-1), var(--accent-bg));
}

/* 列表样式 */
ul,
ol {
  padding-left: 1.5em;
  margin: 1em 0;
}

li {
  margin: 0.5em 0;
}

/* 引用样式 - 使用渐变边框和背景 */
blockquote {
  border-left: 4px solid var(--primary-400);
  margin: 1.5em 0;
  padding-left: 1.5em;
  font-style: italic;
  color: var(--text-2);
  background: var(--accent-bg);
  background-image: var(
    --accent-bg,
    linear-gradient(135deg, rgba(255, 87, 51, 0.1), rgba(255, 138, 0, 0.1))
  );
  border-radius: 0 var(--border-radius) var(--border-radius) 0;
  padding: 1em;
  position: relative;
  overflow: hidden;
}

blockquote::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 4px;
  background: var(--primary-gradient);
  border-radius: 0 2px 2px 0;
}

/* 水平线 - 使用渐变 */
hr {
  border: none;
  height: 2px;
  background: var(--border-base);
  background-image: var(--border-base, var(--primary-gradient));
  margin: 2em 0;
  border-radius: 1px;
  opacity: 0.6;
}

/* 图片样式 - 使用渐变边框 */
img {
  max-width: 100%;
  height: auto;
  border-radius: var(--border-radius);
  border: 2px solid var(--border-subtle);
  background: var(--surface-gradient-0);
  padding: 2px;
  box-shadow: var(--shadow-card);
  transition: all var(--transition-base);
  position: relative;
}

img::before {
  content: '';
  position: absolute;
  top: -2px;
  left: -2px;
  right: -2px;
  bottom: -2px;
  background: var(--border-base);
  background-image: var(--border-base, var(--primary-gradient));
  border-radius: var(--border-radius);
  z-index: -1;
  opacity: 0.5;
}

img:hover {
  border-color: var(--primary-400);
  box-shadow: var(--shadow-primary);
  transform: translateY(-2px);
}

img:hover::before {
  opacity: 1;
}

/* 工具类 */
.text-center {
  text-align: center;
}
.text-right {
  text-align: right;
}
.text-left {
  text-align: left;
}

.mt-1 {
  margin-top: 0.25em;
}
.mt-2 {
  margin-top: 0.5em;
}
.mt-3 {
  margin-top: 1em;
}
.mt-4 {
  margin-top: 1.5em;
}
.mt-5 {
  margin-top: 2em;
}

.mb-1 {
  margin-bottom: 0.25em;
}
.mb-2 {
  margin-bottom: 0.5em;
}
.mb-3 {
  margin-bottom: 1em;
}
.mb-4 {
  margin-bottom: 1.5em;
}
.mb-5 {
  margin-bottom: 2em;
}

.p-1 {
  padding: 0.25em;
}
.p-2 {
  padding: 0.5em;
}
.p-3 {
  padding: 1em;
}
.p-4 {
  padding: 1.5em;
}
.p-5 {
  padding: 2em;
}

.d-flex {
  display: flex;
}
.flex-column {
  flex-direction: column;
}
.justify-center {
  justify-content: center;
}
.align-center {
  align-items: center;
}
.flex-wrap {
  flex-wrap: wrap;
}

/* 状态颜色类 */
.text-success {
  color: var(--success);
}
.text-warning {
  color: var(--warning);
}
.text-error {
  color: var(--error);
}
.text-info {
  color: var(--info);
}

.bg-success {
  background: var(--success-gradient);
}
.bg-warning {
  background: var(--warning-gradient);
}
.bg-error {
  background: var(--error-gradient);
}
.bg-info {
  background: var(--info-gradient);
}

/* 边框颜色类 - 使用渐变外发光效果 */
.border-success {
  border: 2px solid var(--success);
  box-shadow: 0 0 0 2px var(--success), 0 0 10px var(--success);
}
.border-warning {
  border: 2px solid var(--warning);
  box-shadow: 0 0 0 2px var(--warning), 0 0 10px var(--warning);
}
.border-error {
  border: 2px solid var(--error);
  box-shadow: 0 0 0 2px var(--error), 0 0 10px var(--error);
}
.border-info {
  border: 2px solid var(--info);
  box-shadow: 0 0 0 2px var(--info), 0 0 10px var(--info);
}

/* 圆角类 */
.rounded {
  border-radius: var(--border-radius);
}
.rounded-lg {
  border-radius: var(--border-radius-lg);
}
.rounded-full {
  border-radius: 9999px;
}

/* 阴影类 */
.shadow-sm {
  box-shadow: var(--shadow-primary);
}
.shadow-md {
  box-shadow: var(--shadow-accent);
}
.shadow-lg {
  box-shadow: var(--shadow-elevated);
}

/* 渐变背景类 */
.bg-gradient-primary {
  background: var(--primary-gradient);
}
.bg-gradient-accent {
  background: var(--accent-gradient);
}
.bg-gradient-success {
  background: var(--success-gradient);
}

/* 渐变文字类 */
.text-gradient-primary {
  background: var(--primary-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.text-gradient-accent {
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* 动画类 */
.animate-pulse {
  animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}
@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

.animate-spin {
  animation: spin 1s linear infinite;
}
@keyframes spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

/* 过渡类 */
.transition-all {
  transition: all var(--transition-base);
}
.transition-colors {
  transition: color var(--transition-base), background-color var(--transition-base);
}
.transition-transform {
  transition: transform var(--transition-base);
}

/* 隐藏类 */
.hidden {
  display: none;
}
.visible {
  display: block;
}
.invisible {
  visibility: hidden;
}

/* 响应式设计 */
@media (max-width: 768px) {
  :root {
    --font-size: 14px;
    --sidebar-width: 200px;
  }
  body {
    font-size: var(--font-size);
  }
  .card {
    padding: 1em;
  }
  table {
    display: block;
    overflow-x: auto;
  }
}

@media (max-width: 480px) {
  :root {
    --font-size: 13px;
    --sidebar-width: 180px;
  }
  h1 {
    font-size: 2em;
  }
  h2 {
    font-size: 1.5em;
  }
  h3 {
    font-size: 1.25em;
  }
  .card {
    padding: 0.75em;
  }
}

/* 打印样式 */
@media print {
  :root {
    --bg-gradient-0: #ffffff;
    --text-primary: #000000;
    --text-0: #000000;
    --text-1: #333333;
    --text-2: #666666;
  }
  body {
    background: white;
    color: black;
    font-size: 12pt;
  }
  a {
    color: black;
    text-decoration: underline;
  }
  .no-print {
    display: none !important;
  }
  .card {
    border: 1px solid #ccc;
    box-shadow: none;
  }
  ::-webkit-scrollbar {
    display: none;
  }
}

/* 主题切换动画 */
.theme-transition * {
  transition: background-color var(--transition-slow), color var(--transition-slow),
    border-color var(--transition-slow), box-shadow var(--transition-slow);
}

/* 高对比度模式 */
@media (prefers-contrast: high) {
  :root {
    --text-0: #ffffff;
    --text-1: #ffffff;
    --text-2: #e0e0e0;
    --text-3: #c0c0c0;
    --border-base: rgba(255, 255, 255, 0.5);
    --border-strong: rgba(255, 255, 255, 0.8);
  }
  [data-theme='light'] {
    --text-0: #000000;
    --text-1: #000000;
    --text-2: #333333;
    --text-3: #666666;
    --border-base: rgba(0, 0, 0, 0.5);
    --border-strong: rgba(0, 0, 0, 0.8);
  }
}

/* 减少动画模式 */
@media (prefers-reduced-motion: reduce) {
  :root {
    --transition-fast: 0ms;
    --transition-base: 0ms;
    --transition-slow: 0ms;
    --transition-bounce: 0ms;
  }
  * {
    animation-duration: 0ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0ms !important;
  }
}

/* ==================== 熔岩火焰主题 ==================== */
/* 包含日间和夜间两种模式，根据 data-theme 属性切换 */
/* 设计特点：暖色调渐变、强烈对比、火焰效果 */

/* ==================== ⚠️ 重要提示：渐变背景设计 ⚠️ ==================== */
/* 
 * 🔴 渐变背景颜色变量（必须修改）：
 * 这些变量控制整个应用的渐变背景颜色，是主题的核心！
 * 请根据你的设计需求修改以下变量：
 * 
 * --bg-gradient-0 到 --bg-gradient-4: 基础渐变背景色层次
 * --surface-gradient-0 到 --surface-gradient-3: 表面渐变颜色
 * 
 * 建议：使用互补色或类似色调创建和谐渐变
 */

/* ==================== 夜间模式（默认）- 熔岩火焰 ==================== */
:root {
    /* ==================== 🔴 渐变背景颜色（必须修改） ==================== */
    /* 基础渐变背景色 - 深红到深橙渐变（熔岩效果） */
    --bg-gradient-0: linear-gradient(135deg, #0a0a0a 0%, #1a0a0a 50%, #2a0a0a 100%);  /* 🔴 最深层渐变背景 */
    --bg-gradient-1: linear-gradient(135deg, #1a0a0a 0%, #2a0a0a 50%, #3a0a0a 100%);  /* 🔴 主渐变背景 */
    --bg-gradient-2: linear-gradient(135deg, #2a0a0a 0%, #3a0a0a 50%, #4a0a0a 100%);  /* 🔴 次要渐变背景 */
    --bg-gradient-3: linear-gradient(135deg, #3a0a0a 0%, #4a0a0a 50%, #5a0a0a 100%);  /* 🔴 三级渐变背景 */
    --bg-gradient-4: linear-gradient(135deg, #4a0a0a 0%, #5a0a0a 50%, #6a0a0a 100%);  /* 🔴 四级渐变背景 */

    /* 表面渐变颜色 - 用于卡片、面板、按钮等（火焰表面效果） */
    --surface-gradient-0: linear-gradient(145deg, #2a0a0a 0%, #3a0a0a 100%);  /* 🔴 表面0渐变 */
    --surface-gradient-1: linear-gradient(145deg, #3a0a0a 0%, #4a0a0a 100%);  /* 🔴 表面1渐变 */
    --surface-gradient-2: linear-gradient(145deg, #4a0a0a 0%, #5a0a0a 100%);  /* 🔴 表面2渐变（按钮默认背景） */
    --surface-gradient-3: linear-gradient(145deg, #5a0a0a 0%, #6a0a0a 100%);  /* 🔴 表面3渐变（按钮hover背景） */

    /* 兼容纯色变量（用于不支持渐变的元素） */
    --bg-0: #0a0a0a;
    --bg-1: #1a0a0a;
    --bg-2: #2a0a0a;
    --bg-3: #3a0a0a;
    --bg-4: #4a0a0a;

    --surface-0: #2a0a0a;
    --surface-1: #3a0a0a;
    --surface-2: #4a0a0a;
    --surface-3: #5a0a0a;

    /* 边框颜色 - 火焰色边框 */
    --border-subtle: rgba(255, 87, 51, 0.2);
    --border-base: linear-gradient(90deg, rgba(255, 87, 51, 0.4), rgba(255, 138, 0, 0.4));
    --border-strong: linear-gradient(90deg, rgba(255, 87, 51, 0.6), rgba(255, 138, 0, 0.6));
    --border-emphasis: linear-gradient(90deg, rgba(255, 87, 51, 0.8), rgba(255, 138, 0, 0.8));

    /* 文字颜色 - 亮色文字确保可读性 */
    --text-0: #ffffff;
    --text-1: #ffeded;
    --text-2: #ffcccc;
    --text-3: #ffaaaa;
    --text-4: #ff8888;

    /* 主色调 - 橙色系渐变（火焰核心色） */
    --primary-400: #ff5733;
    --primary-500: #ff8a00;
    --primary-600: #ffa500;
    --primary-gradient: linear-gradient(135deg, #ff5733 0%, #ff8a00 50%, #ffa500 100%);
    --primary-gradient-hover: linear-gradient(135deg, #ff8a00 0%, #ffa500 50%, #ffc107 100%);

    /* 强调色 - 红色系渐变（火焰外围色） */
    --accent-500: #ff3333;
    --accent-600: #ff5555;
    --accent-gradient: linear-gradient(135deg, #ff3333 0%, #ff5555 50%, #ff7777 100%);
    --accent-gradient-hover: linear-gradient(135deg, #ff5555 0%, #ff7777 50%, #ff9999 100%);

    /* 状态颜色 - 渐变效果 */
    --success: #4CAF50;
    --success-gradient: linear-gradient(135deg, #4CAF50 0%, #66BB6A 50%, #81C784 100%);
    --warning: #FF9800;
    --warning-gradient: linear-gradient(135deg, #FF9800 0%, #FFB74D 50%, #FFCC80 100%);
    --error: #F44336;
    --error-gradient: linear-gradient(135deg, #F44336 0%, #EF5350 50%, #E57373 100%);
    --info: #2196F3;
    --info-gradient: linear-gradient(135deg, #2196F3 0%, #42A5F5 50%, #64B5F6 100%);

    /* 代码高亮颜色 */
    --code-keyword: #ff5733;
    --code-string: #ff8a00;
    --code-number: #ffa500;
    --code-comment: #ff8888;
    --code-function: #ff3333;

    /* 兼容旧变量 */
    --bg-primary: var(--bg-1);
    --bg-secondary: var(--bg-2);
    --bg-tertiary: var(--bg-3);
    --bg-body: var(--bg-0);
    --bg-pane: var(--surface-0);
    --text-primary: var(--text-1);
    --text-secondary: var(--text-2);
    --text-muted: var(--text-3);
    --accent-blue: var(--primary-400);
    --accent-purple: var(--accent-500);
    --border: var(--border-base);
    --border-light: var(--border-subtle);
    --accent-bg: linear-gradient(135deg, rgba(255, 87, 51, 0.15), rgba(255, 138, 0, 0.15));
    --code-bg: linear-gradient(135deg, rgba(42, 10, 10, 0.9), rgba(58, 10, 10, 0.9));

    /* 界面尺寸 */
    --sidebar-width: 220px;
    --font-size: 15px;
    --border-radius: 10px;
    --border-radius-lg: 16px;

    /* 字体 */
    --font-ui: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    --font-read: 'Inter', 'Microsoft YaHei', sans-serif;
    --font-code: 'JetBrains Mono', Consolas, monospace;

    /* ==================== 🔴 滚动条样式变量（修复版） ==================== */
    /* 滚动条尺寸 */
    --scrollbar-width: 10px;
    --scrollbar-height: 10px;
    --scrollbar-thumb-radius: 6px;
    --scrollbar-track-radius: 10px;

    /* 滚动条颜色（用于Firefox，不支持渐变） */
    --scrollbar-thumb-color: var(--primary-400, #ff5733);
    --scrollbar-thumb-hover-color: var(--primary-500, #ff8a00);
    --scrollbar-track-color: var(--bg-2, #2a0a0a);

    /* 滚动条透明度 */
    --scrollbar-thumb-opacity: 0.9;
    --scrollbar-thumb-hover-opacity: 1;
    --scrollbar-track-opacity: 0.4;

    /* 滚动条渐变（用于WebKit浏览器） */
    --scrollbar-thumb-gradient: linear-gradient(135deg, var(--primary-400) 0%, var(--accent-500) 100%);
    --scrollbar-thumb-hover-gradient: linear-gradient(135deg, var(--primary-500) 0%, var(--accent-600) 100%);

    /* 滚动条阴影效果 */
    --scrollbar-thumb-shadow: 0 2px 10px rgba(255, 87, 51, 0.5), inset 0 1px 0 rgba(255, 255, 255, 0.2);
    --scrollbar-thumb-hover-shadow: 0 4px 20px rgba(255, 87, 51, 0.7), inset 0 1px 0 rgba(255, 255, 255, 0.3);

    /* 选中文本样式 */
    --selection-bg-color: linear-gradient(135deg, rgba(255, 87, 51, 0.4), rgba(255, 138, 0, 0.4));
    --selection-text-color: var(--text-0);
    --selection-border-width: 1px;
    --selection-border-color: var(--primary-400);

    /* 盒子内外边距 */
    --box-margin-top: 0px;
    --box-margin-right: 0px;
    --box-margin-bottom: 0px;
    --box-margin-left: 0px;
    --box-margin: var(--box-margin-top) var(--box-margin-right) var(--box-margin-bottom) var(--box-margin-left);
    --box-padding-top: 0px;
    --box-padding-right: 0px;
    --box-padding-bottom: 0px;
    --box-padding-left: 0px;
    --box-padding: var(--box-padding-top) var(--box-padding-right) var(--box-padding-bottom) var(--box-padding-left);

    /* 盒子边框 */
    --box-border-width: 0px;
    --box-border-style: solid;
    --box-border-color: transparent;
    --box-border: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-top: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-right: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-bottom: var(--box-border-width) var(--box-border-style) var(--box-border-color);
    --box-border-left: var(--box-border-width) var(--box-border-style) var(--box-border-color);

    /* 新增：阴影效果 - 火焰发光 */
    --shadow-primary: 0 4px 20px rgba(255, 87, 51, 0.4), 0 8px 30px rgba(255, 138, 0, 0.3);
    --shadow-accent: 0 4px 20px rgba(255, 51, 51, 0.4), 0 8px 30px rgba(255, 87, 51, 0.3);
    --shadow-elevated: 0 10px 40px rgba(255, 0, 0, 0.3), 0 0 20px rgba(255, 87, 51, 0.2);

    /* 新增：动画效果 */
    --transition-fast: 150ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-base: 200ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 300ms cubic-bezier(0.4, 0, 0.2, 1);
    --transition-bounce: 400ms cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

/* ==================== 日间模式 - 森林绿意 ==================== */
[data-theme="light"] {
